# Generates tools.go from the tool directives in go.mod.

set -o pipefail

OUTPUT="tools.go"

# Extract tool packages from go.mod.
packages=$(go mod edit -json "go.mod" | jq -r '.Tool[] | "_ \"" + .Path + "\""')

cat > "$OUTPUT" << EOF
//go:build tools
// The "tools" build tag is never set, it is there to exclude the file from normal builds and linting

// Code generated by scripts/generate-tools.sh. DO NOT EDIT.

package tools

import (
    $packages
)
EOF

gofmt -w "$OUTPUT"
go mod tidy

echo "Generated $OUTPUT and ran go mod tidy."
